SELECT AVG(feature_importance) AS average_time_feature_importance
FROM features
WHERE prefix = 'time';

SELECT feature_name
FROM features
WHERE feature_importance = (SELECT MAX(feature_importance) FROM features);

SELECT COUNT(DISTINCT user_id) AS unique_data_scientists_count
FROM users
WHERE role = 'data scientist';

SELECT COUNT(*) AS feature_count
FROM features
WHERE prefix = '3';
